    project: otherProject.id,
    title: "Cross-Project Target Issue",
});
const crossProjectRelatesTo = new gitlab.ProjectIssueLink("cross_project_relates_to", {
    project: example.id,
    issueIid: source.iid,
    targetProjectId: otherProject.id,
    targetIssueIid: crossTarget.iid,
    linkType: "relates_to",
});
